        return {}

    counts = {}
    for char in test:
        if char in counts:
            counts[char] += 1
        else:
            counts[char] = 1

    # Sort by count descending, then by char ascending for ties
    sorted_counts = sorted(counts.items(), key=lambda x: (-x[1], x[0]))

    return {char: count for char, count in sorted_counts}

