def split_words(txt):
    # Split on whitespace
    words = txt.split()

    # If no whitespace exists, split on commas
    if not words:
        return [0]

    # Check for commas
    if "," in words:
        words = words.split(",")

    # If no commas, count odd-order lowercase letters
    count = 0
    for word in words:
        if word.islower():
            count += ord(word[0])

    return count

