    cycpattern_check("abcd","abd") => False
    cycpattern_check("hello","ell") => True
    cycpattern_check("whassup","psus") => False
    cycpattern_check("abab","baa") => True
    cycpattern_check("efef","eeff") => False
    cycpattern_check("himenss","simen") => True

    """
    def is_substring(s, t):
        return t in s

    def rotate(s):
        return s[1:] + s[:1]

    def is_rotated(s):
        return any(is_substring(rotated(s), t) for t in b)

    return is_substring(a, b) or is_rotated(a)

def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    roman_map = {
        'I': 1,
        'V': 5,
        'X': 10,
        'L': 50,
        'C': 100,
        'D': 500,
        'M': 1000,
    }

    def is_greater_than(sub):
        return sub > roman_map.get(sub, 0)

    result = []
    current = 0
    for num in range(1, number + 1):
        if num <= 1000:
            if num in roman_map:
                current += roman_map[num]
            else:
                current += 1
        else:
            current += 1

        if current > 1000:
            break

        if current == 1000:
            result.append('M')
            current = 0
        elif current == 900:
            result.append('CM')
            current = 0
        elif current == 500:
            result.append('CD')
            current = 0
        elif current == 400:
            result.append('CD')
            current = 0
        elif current == 90:
            result.append('XC')
            current = 0
        elif current == 40:
            result.append('XC')
            current = 0
        elif current == 9:
            result.append('IX')
            current = 0
        elif current == 4:
            result.append('IV')
            current = 0
        elif current == 1:
            result.append('I')
            current = 0

    return "".join(roman_map[letter] for letter in result)

def find_max(words):
    """Write a function that accepts a list of strings.
    The list contains different words. Return the word with maximum number
    of unique characters. If multiple strings have maximum number of unique
    characters, return the one which comes first in lexicographical order.

    find_max(["name", "of", "string"]) == "string"
    find_max(["name", "enam", "game"]) == "enam"
    find_max(["aaaaaaa", "bb" ,"cc"]) == ""aaaaaaa"
    """
    def count_unique_chars(word):
        return len(set(word))

    def compare_words(w1, w2):
        return count_unique_chars(w1) - count_unique_chars(w2)

    def sort_words(w1, w2):
        if count_unique_chars(w1) == count_unique_chars(w2):
            return w1 < w2
        return count_unique_chars(w1) > count_unique_chars(w2)

    def find_max(words):
        if not words:
            return ""

        sorted_words = sorted(words, key=sort_words)
        return sorted_words[0]

    return find_max(words)

